def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class synced with the
    main dictionary on every operation that mutates it (`__setitem__`, `__delitem__`, `update`, etc.).

    This is used instead of subclassing `UserDict` for performance reasons: dict subclasses backed by an actual
    `dict` are significantly faster than `UserDict`, which stores its data in a separate `data` attribute and
    delegates every operation to it.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "_keep_dicts_synced"
    return wrapper


